#include "interface.h"

#include <cstdint>
#include <vector>

namespace {

static inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}  // namespace

uint64_t csr_offsets_hash(const std::vector<uint32_t>& row_ids, uint32_t rows, int iters) {
  const std::size_t nnz = row_ids.size();
  std::vector<uint32_t> offsets(static_cast<std::size_t>(rows) + 1u);
  uint64_t hash = 0;

  for (int iter = 0; iter < iters; ++iter) {
    offsets[0] = 0;

    std::size_t i = 0;
    uint32_t current_row = 0;
    uint32_t prefix = 0;

    while (i < nnz) {
      const uint32_t r = row_ids[i];

      while (current_row < r) {
        offsets[static_cast<std::size_t>(current_row + 1u)] = prefix;
        ++current_row;
      }

      std::size_t j = i + 1;
      while (j < nnz && row_ids[j] == r) {
        ++j;
      }

      prefix += static_cast<uint32_t>(j - i);
      offsets[static_cast<std::size_t>(r + 1u)] = prefix;
      current_row = r + 1u;
      i = j;
    }

    while (current_row < rows) {
      offsets[static_cast<std::size_t>(current_row + 1u)] = prefix;
      ++current_row;
    }

    hash = 1469598103934665603ULL;
    for (uint32_t v : offsets) {
      hash = mix(hash, v);
    }
  }

  return hash;
}
